import{_ as i,o as a,c as e,O as t}from"./chunks/framework.c4f51971.js";const s=JSON.parse('{"title":"部署方式","description":"","frontmatter":{},"headers":[],"relativePath":"product/deployment.md","filePath":"product/deployment.md","lastUpdated":1775624478000}'),o={name:"product/deployment.md"};function r(p,l,d,u,n,h){return a(),e("div",null,l[0]||(l[0]=[t('<h1 id="部署方式" tabindex="-1">部署方式 <a class="header-anchor" href="#部署方式" aria-label="Permalink to &quot;部署方式&quot;">​</a></h1><p>SmartFlow 的部署思路不是只有一种，而是根据数据边界、客户规模和执行位置做组合。</p><h2 id="_1-单租户交付模式" tabindex="-1">1. 单租户交付模式 <a class="header-anchor" href="#_1-单租户交付模式" aria-label="Permalink to &quot;1. 单租户交付模式&quot;">​</a></h2><p>适合：</p><ul><li>企业客户项目交付</li><li>需要独立访问地址</li><li>需要和其他客户完全隔离</li></ul><p>特点：</p><ul><li>一个客户一个租户</li><li>客户能力与数据边界清晰</li><li>适合长期维护和持续扩展</li></ul><h2 id="_2-平台治理模式" tabindex="-1">2. 平台治理模式 <a class="header-anchor" href="#_2-平台治理模式" aria-label="Permalink to &quot;2. 平台治理模式&quot;">​</a></h2><p>适合：</p><ul><li>平台方统一管理多个客户</li><li>需要公告、模板、日志和台账总控</li><li>需要跨租户治理但不打破隔离</li></ul><p>特点：</p><ul><li><code>public</code> 作为平台治理域</li><li>租户保持独立运行</li><li>平台级能力和租户级能力分流</li></ul><h2 id="_3-免费入口模式" tabindex="-1">3. 免费入口模式 <a class="header-anchor" href="#_3-免费入口模式" aria-label="Permalink to &quot;3. 免费入口模式&quot;">​</a></h2><p>适合：</p><ul><li>产品体验入口</li><li>个人开发者试用</li><li>公开展示平台能力</li></ul><p>特点：</p><ul><li>入口语义更轻</li><li>更强调上手速度和体验路径</li><li>为后续团队版、企业版升级提供前置入口</li></ul><h2 id="_4-本地混合执行模式" tabindex="-1">4. 本地混合执行模式 <a class="header-anchor" href="#_4-本地混合执行模式" aria-label="Permalink to &quot;4. 本地混合执行模式&quot;">​</a></h2><p>适合：</p><ul><li>文件和数据不能全部上云</li><li>任务依赖本地环境或内网资源</li><li>需要保留本地执行灵活性</li></ul><p>特点：</p><ul><li>平台负责入口、规划、权限和审计</li><li>本地环境负责执行</li><li>CLI / Agent 负责桥接</li></ul><h2 id="_5-未来边缘与设备模式" tabindex="-1">5. 未来边缘与设备模式 <a class="header-anchor" href="#_5-未来边缘与设备模式" aria-label="Permalink to &quot;5. 未来边缘与设备模式&quot;">​</a></h2><p>这是 <code>4.0</code> 的公开方向之一。</p><p>适合：</p><ul><li>需要把执行端从脚本环境延伸到边缘节点</li><li>需要统一治理设备能力包</li><li>需要对高风险动作做权限和审计控制</li></ul><p>特点：</p><ul><li>能力单元不再局限于脚本</li><li>执行端可能是本地 Agent、边缘节点或设备插件</li><li>Web 控制面继续作为统一治理入口</li></ul><h2 id="_6-如何选择" tabindex="-1">6. 如何选择 <a class="header-anchor" href="#_6-如何选择" aria-label="Permalink to &quot;6. 如何选择&quot;">​</a></h2><p>如果你当前重点是：</p><ul><li>客户交付：优先单租户交付模式</li><li>平台运营：加上平台治理模式</li><li>获客与试用：加上免费入口模式</li><li>私有数据执行：补本地混合执行模式</li><li>长期设备化延伸：预留边缘与设备模式</li></ul><p>SmartFlow 的价值不在于强迫所有用户走同一条部署路径，而在于用同一套治理逻辑覆盖不同执行位置。</p>',32)]))}const m=i(o,[["render",r]]);export{s as __pageData,m as default};
